// Fill the certificate template with the values the game sent.
const b = ($input.first().json.body) || {};
const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const TEMPLATE = "<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  @page { size: 297mm 210mm; margin: 0; }
  html, body { margin: 0; padding: 0; width: 297mm; height: 210mm; font-family: 'Poppins', 'Segoe UI', Verdana, sans-serif; }
  .sheet { position: relative; width: 297mm; height: 210mm; box-sizing: border-box; background: linear-gradient(135deg, #fff8e6 0%, #fef2e0 100%); overflow: hidden; }
  .border-outer { position: absolute; inset: 8mm; border: 3mm solid #1a3a5c; border-radius: 6mm; box-sizing: border-box; }
  .border-inner { position: absolute; inset: 12mm; border: 1.2mm dashed #ffb703; border-radius: 4mm; box-sizing: border-box; }
  .road-strip { position: absolute; top: 0; left: 0; width: 100%; height: 14mm; background: #2b2d42; z-index: 0; }
  .road-strip::after { content: ""; position: absolute; top: 50%; left: 0; width: 100%; height: 2.2mm; margin-top: -1.1mm; background-image: repeating-linear-gradient(to right, #ffd166 0mm, #ffd166 14mm, transparent 14mm, transparent 24mm); }
  .corner-icon { position: absolute; z-index: 1; }
  .corner-icon.tl { top: 16mm; left: 16mm; width: 22mm; height: 22mm; }
  .corner-icon.tr { top: 16mm; right: 16mm; width: 22mm; height: 22mm; }
  .corner-icon.bl { bottom: 9mm; left: 9mm; width: 16mm; height: 16mm; }
  .corner-icon.br { bottom: 9mm; right: 9mm; width: 16mm; height: 16mm; }
  .content { position: relative; z-index: 2; padding: 26mm 26mm 0 26mm; text-align: center; box-sizing: border-box; }
  .logo-slot { height: 16mm; margin: 0 auto 4mm auto; display: flex; align-items: center; justify-content: center; }
  .logo-slot img { height: 16mm; width: auto; }
  .badge-line { font-size: 11pt; letter-spacing: 3px; text-transform: uppercase; color: #e63946; font-weight: 700; margin-bottom: 2mm; }
  h1.title { font-size: 32pt; color: #1a3a5c; margin: 0 0 3mm 0; font-weight: 800; letter-spacing: 1px; }
  .subtitle { font-size: 12pt; color: #4a4a4a; margin-bottom: 8mm; font-style: italic; }
  .presented-to { font-size: 11pt; text-transform: uppercase; letter-spacing: 2px; color: #6a6a6a; margin-bottom: 2mm; }
  .name-line { font-size: 26pt; font-weight: 700; color: #e63946; font-family: 'Brush Script MT', 'Segoe Script', cursive; border-bottom: 0.6mm solid #ffb703; display: inline-block; padding: 0 14mm 2mm 14mm; margin-bottom: 6mm; min-width: 140mm; }
  .body-text { font-size: 12pt; color: #333; line-height: 1.6; max-width: 200mm; margin: 0 auto 5mm auto; }
  .challenge-name { font-weight: 700; color: #1a3a5c; }
  .stars { font-size: 15pt; letter-spacing: 4mm; color: #ffb703; margin-bottom: 4mm; }
  .footer { position: absolute; bottom: 22mm; left: 0; right: 0; height: 20mm; z-index: 2; }
  .footer-block { position: absolute; bottom: 0; width: 58mm; text-align: center; box-sizing: border-box; }
  .footer-block.left { left: 24mm; }
  .footer-block.right { right: 24mm; }
  .footer-block.center { left: 50%; margin-left: -13mm; width: 26mm; }
  .footer-line { border-top: 0.4mm solid #1a3a5c; margin-bottom: 1.5mm; }
  .footer-label { font-size: 8.5pt; color: #555; text-transform: uppercase; letter-spacing: 1px; white-space: nowrap; }
  .footer-value { font-size: 9.5pt; color: #1a3a5c; font-weight: 600; margin-bottom: 1.5mm; line-height: 1.25; overflow-wrap: break-word; }
  .seal { width: 22mm; height: 22mm; border-radius: 50%; background: radial-gradient(circle at 35% 30%, #ffe08a, #ffb703 60%, #e63946 100%); display: flex; flex-direction: column; align-items: center; justify-content: center; color: #fff; font-weight: 800; font-size: 7pt; text-align: center; line-height: 1.3; margin: 0 auto; }
  .cert-id { position: absolute; bottom: 12mm; left: 0; right: 0; text-align: center; font-size: 8pt; color: #999; z-index: 2; }
</style>
</head>
<body>
  <div class="sheet">
    <div class="road-strip"></div>
    <div class="border-outer"></div>
    <div class="border-inner"></div>
    <svg class="corner-icon tl" viewBox="0 0 64 64"><polygon points="32,8 46,54 18,54" fill="#ff8c42" stroke="#1a3a5c" stroke-width="2"/><rect x="14" y="54" width="36" height="6" fill="#1a3a5c"/><rect x="22" y="30" width="20" height="6" fill="#fff"/></svg>
    <svg class="corner-icon tr" viewBox="0 0 64 64"><polygon points="32,8 46,54 18,54" fill="#ff8c42" stroke="#1a3a5c" stroke-width="2"/><rect x="14" y="54" width="36" height="6" fill="#1a3a5c"/><rect x="22" y="30" width="20" height="6" fill="#fff"/></svg>
    <svg class="corner-icon bl" viewBox="0 0 64 64"><circle cx="32" cy="32" r="26" fill="#2b9348" stroke="#1a3a5c" stroke-width="2"/><path d="M20 33 L28 41 L45 22" stroke="#fff" stroke-width="5" fill="none" stroke-linecap="round" stroke-linejoin="round"/></svg>
    <svg class="corner-icon br" viewBox="0 0 64 64"><circle cx="32" cy="32" r="26" fill="#2b9348" stroke="#1a3a5c" stroke-width="2"/><path d="M20 33 L28 41 L45 22" stroke="#fff" stroke-width="5" fill="none" stroke-linecap="round" stroke-linejoin="round"/></svg>
    <div class="content">
      <div class="logo-slot"><img src="navigator_logo.svg" alt="Navigator+ Vitality logo" onerror="this.style.display='none'"></div>
      <div class="badge-line">Navigator+ Vitality &mdash; Road Safety Challenge</div>
      <h1 class="title">Certificate of Completion</h1>
      <div class="subtitle">Awarded for successfully completing the challenge</div>
      <div class="presented-to">This certificate is proudly presented to</div>
      <div class="name-line">{{PARTICIPANT_NAME}}</div>
      <div class="body-text">
        for successfully completing the <span class="challenge-name">{{CHALLENGE_NAME}}</span> challenge,
        demonstrating knowledge and commitment to safer roads for everyone.
      </div>
      <div class="stars">&#9733; &#9733; &#9733;</div>
    </div>
    <div class="footer">
      <div class="footer-block left">
        <div class="footer-line"></div>
        <div class="footer-value">{{DATE}}</div>
        <div class="footer-label">Date Completed</div>
      </div>
      <div class="footer-block center">
        <div class="seal"><span>OFFICIAL</span><span>SEAL</span></div>
      </div>
      <div class="footer-block right">
        <div class="footer-line"></div>
        <div class="footer-value">{{ISSUER_NAME}}</div>
        <div class="footer-label">Issued By / Signature</div>
      </div>
    </div>
    <div class="cert-id">Certificate ID: {{CERT_ID}}</div>
  </div>
</body>
</html>
";
const html = TEMPLATE
  .replace(/{{PARTICIPANT_NAME}}/g, esc(b.participantName || b.name || 'Participant'))
  .replace(/{{CHALLENGE_NAME}}/g,   esc(b.challengeName || 'Road Safety'))
  .replace(/{{DATE}}/g,             esc(b.date || new Date().toLocaleDateString('en-GB')))
  .replace(/{{ISSUER_NAME}}/g,      esc(b.issuerName || 'Navigator+ Vitality'))
  .replace(/{{CERT_ID}}/g,          esc(b.certId || ('NV-' + Date.now())));
return [{ json: { html, name: b.name || b.participantName || 'Participant', score: b.score || 0, email: b.email || '' } }];
